mapper.select:
SELECT id, name, room_type, created_by, is_archived, created_at, updated_at
FROM gw_chat_rooms
WHERE id = #{id}

SELECT EXISTS(
    SELECT 1 FROM gw_chat_room_members
    WHERE room_id = #{roomId} AND user_id = #{userId}
)

mapper.update:
UPDATE gw_chat_room_members
SET last_read_at = NOW()
WHERE room_id = #{roomId} AND user_id = #{userId}

mapper.select:
SELECT m.id, m.room_id, m.sender_id, m.content, m.message_type, m.edited_at, m.deleted_at, m.created_at, u.name AS sender_name FROM gw_messages m JOIN itsm_users u ON m.sender_id = u.id WHERE m.room_id = #{roomId} AND m.deleted_at IS NULL
AND m.id < #{before}
ORDER BY m.created_at DESC LIMIT #{limit}

SELECT COUNT(*)
FROM gw_messages m
JOIN gw_chat_room_members rm ON rm.room_id = m.room_id AND rm.user_id = #{userId}
WHERE m.room_id = #{roomId}
  AND m.deleted_at IS NULL
  AND m.created_at > COALESCE(rm.last_read_at, '1970-01-01')
